package com.cognizant.week4.hibernatecrud;

import org.hibernate.Session; import org.hibernate.SessionFactory; import org.springframework.stereotype.Repository;
@Repository public class EmployeeDao { private final SessionFactory factory; public EmployeeDao(SessionFactory factory) { this.factory = factory; } public Employee save(Employee employee) { try (Session session = factory.openSession()) { session.beginTransaction(); session.persist(employee); session.getTransaction().commit(); return employee; } } public Employee fetch(Long id) { try (Session session = factory.openSession()) { return session.get(Employee.class, id); } } public void update(Employee employee) { try (Session session = factory.openSession()) { session.beginTransaction(); session.merge(employee); session.getTransaction().commit(); } } public void delete(Long id) { try (Session session = factory.openSession()) { session.beginTransaction(); Employee employee = session.get(Employee.class, id); if (employee != null) session.remove(employee); session.getTransaction().commit(); } } }
